'use strict';

// ═══════════════════════════ DATA — EXERCICES ═══════════════════════════
const EL=[
{id:"A",f:"A",name:"Exercice A",desc:"Pompes classiques : mains et pieds au sol, corps droit et tendu, écart mains environ 2× la largeur des épaules. Descendre jusqu'à toucher presque le sol, remonter en tendant les bras. Inspirer en descendant, souffler en montant.",ms:["Pectoraux","Triceps","Épaules"],d:1,bar:false,ch:false},
{id:"A1",f:"A",name:"Exercice A1",desc:"Pompes entre 3 chaises : mains écartées de 2× la largeur des épaules sur 2 chaises, pieds sur la 3e. Corps droit et tendu. Descendre le plus bas possible sans forcer, remonter en soufflant. Les chaises doivent être relativement plates avec un appui ferme pour les mains.",ms:["Pectoraux","Triceps","Épaules"],d:1,bar:false,ch:true},
{id:"A2",f:"A",name:"Exercice A2",desc:"Pompes mains sur 2 chaises, pieds sur support à environ 1m du sol (mur, rebord, étagère…). Écart des mains environ 2× la largeur des épaules. Corps tendu, bien droit. Inspirer en descendant, souffler en remontant.",ms:["Pectoraux","Épaules","Triceps"],d:2,bar:false,ch:true},
{id:"A3",f:"A",name:"Exercice A3",desc:"Mains à plat sur support à environ 45cm du sol (tabouret, canapé, banc…), écart des mains 40cm. Pieds au sol. Corps tendu, ne pas cambrer. Descendre la poitrine jusqu'au support en inspirant, remonter en soufflant.",ms:["Milieu de la poitrine","Triceps"],d:2,bar:false,ch:true},
{id:"A4",f:"A",name:"Exercice A4",desc:"Même technique qu'A3. Le support est situé à environ 35cm du sol.",ms:["Milieu de la poitrine","Triceps"],d:2,bar:false,ch:false},
{id:"A5",f:"A",name:"Exercice A5",desc:"Même technique qu'A3. Le support est situé à environ 25cm du sol.",ms:["Milieu de la poitrine","Triceps"],d:2,bar:false,ch:false},
{id:"A6",f:"A",name:"Exercice A6",desc:"Mains et pieds reposent sur deux supports de même hauteur (15cm minimum). Technique identique à A3 ; descendre jusqu'à ce que la poitrine touche les mains. Si nécessaire, remplacer par A5 avec un écart de 25 à 30cm entre les mains.",ms:["Milieu de la poitrine","Triceps"],d:3,bar:false,ch:false},
{id:"A7",f:"A",name:"Exercice A7",desc:"Même descriptif qu'A1 (3 chaises). La distance séparant les mains correspond à la largeur des épaules, contrairement à A1 où la distance est plus importante.",ms:["Pectoraux","Triceps","Épaules"],d:2,bar:false,ch:true},
{id:"A8",f:"A",name:"Exercice A8",desc:"Même principe qu'A7. Les pieds sont posés au sol au lieu d'être sur une chaise. Cible la partie basse des pectoraux.",ms:["Pectoraux (partie basse)"],d:2,bar:false,ch:true},
{id:"A9",f:"A",name:"Exercice A9",desc:"Pompes très serrées : mains sur support à environ 20cm, pieds sur chaise à environ 45cm. Plier les bras pour toucher le support avec le haut de la poitrine, remonter en soufflant. L'écart entre les mains doit être de 15cm maximum. Corps droit pendant le mouvement.",ms:["Triceps","Pectoraux (partie centrale)","Épaules"],d:2,bar:false,ch:true},
{id:"A10",f:"A",name:"Exercice A10",desc:"Même positionnement qu'A7. Faire ici un mouvement circulaire au lieu de descendre bien droit. Imaginer que les épaules sont un axe autour duquel tourne le corps ; dans le même temps, monter et descendre (fléchir et tendre les bras).",ms:["Épaules","Pectoraux","Triceps"],d:3,bar:false,ch:true},
{id:"A11",f:"A",name:"Exercice A11",desc:"Même positionnement qu'A7. Faire ici un mouvement circulaire au lieu de descendre bien droit. Ce mouvement circulaire se fait dans le sens inverse de celui de A10.",ms:["Épaules","Pectoraux","Triceps"],d:3,bar:false,ch:true},
{id:"A12",f:"A",name:"Exercice A12",desc:"Utiliser deux chaises (supports d'environ 45cm de haut) et un meuble d'un mètre à un mètre dix. Placer les chaises côte à côte. Écart entre les mains : 40cm. Pieds sur le meuble, corps en V (fesses en l'air). Inspirer en descendant, souffler en remontant. Corps droit.",ms:["Pectoraux (partie centrale)","Triceps","Épaules"],d:3,bar:false,ch:true},
{id:"B",f:"B",name:"Exercice B",desc:"Dips en appui sur 2 barres parallèles ou montants (~63cm d'écart). Faire une flexion des bras sans que les pieds touchent le sol, plier les jambes si nécessaire. Inspirer en descendant (flexion), souffler en remontant (extension).",ms:["Pectoraux (partie latérale haute)","Épaules","Triceps"],d:1,bar:false,ch:true},
{id:"B1",f:"B",name:"Exercice B1",desc:"Bras tendus en appui sur les barres parallèles. Descendre pour s'arrêter à la moitié du mouvement (bras parallèles au sol), puis remonter en tendant les bras. Lorsqu'on est à mi-chemin, les bras sont parallèles au sol. Inspirer en descendant, souffler en remontant.",ms:["Pectoraux (partie latérale haute)","Épaules","Triceps"],d:2,bar:false,ch:true},
{id:"B2",f:"B",name:"Exercice B2",desc:"Prendre comme référence la demi-flexion de B1 (bras parallèles au sol). Une répétition de B2 consiste à descendre un peu en dessous de la parallèle et à remonter un peu au-dessus sans tendre les bras. Ne jamais descendre à fond ni remonter complètement. Aller le plus vite possible.",ms:["Pectoraux","Épaules"],d:3,bar:false,ch:true},
{id:"C",f:"C",name:"Exercice C",desc:"Tractions à la barre fixe, prise supination (paumes vers le visage), largeur des épaules. Se suspendre bras tendus. En soufflant, monter le menton au-dessus de la barre. Inspirer en descendant, souffler en remontant. Ne pas tendre le cou en arrière.",ms:["Milieu du dos","Biceps"],d:1,bar:true,ch:false},
{id:"C1",f:"C",name:"Exercice C1",desc:"Sauter pour démarrer le mouvement avec le menton au-dessus de la barre. En inspirant, descendre pour ne faire que la moitié du mouvement. En soufflant, remonter. Quand les bras sont parallèles au sol, c'est la moitié du mouvement (le mouvement complet c'est C).",ms:["Milieu du dos","Biceps"],d:2,bar:true,ch:false},
{id:"C2",f:"C",name:"Exercice C2",desc:"Reprendre la technique décrite pour C1. Cette fois, descendre un peu plus bas que la position moyenne (bras parallèles) et remonter un peu plus haut. Ne pas tendre les bras en bas, ne pas monter le menton au-dessus de la barre. Inspirer en descendant, souffler en remontant. Aller le plus vite possible.",ms:["Milieu du dos","Biceps"],d:2,bar:true,ch:false},
{id:"C3",f:"C",name:"Exercice C3",desc:"Reprendre la technique utilisée pour C. Ne faire que les deux tiers du mouvement : descendre assez bas, mais sans tendre les bras.",ms:["Milieu du dos","Biceps"],d:3,bar:true,ch:false},
{id:"C4",f:"C",name:"Exercice C4",desc:"Tractions inversées sous barre basse (80–110cm du sol). Jambes repliées, genoux bien écartés, pieds joints au sol. Paumes tournées vers le haut (supination), écart des mains inférieur à la largeur des épaules. Descendre jusqu'à ce que les bras soient presque tendus en inspirant, remonter en soufflant.",ms:["Épaisseur du dos","Biceps"],d:1,bar:true,ch:false},
{id:"C5",f:"C",name:"Exercice C5",desc:"Reprendre la technique et la respiration de C4. Seule la position des jambes change : jambes tendues sur support à environ 45cm de haut.",ms:["Épaisseur du dos","Biceps"],d:2,bar:true,ch:true},
{id:"C6",f:"C",name:"Exercice C6",desc:"Reprendre la technique et la respiration de C4. Pieds sur une chaise ou support à environ 45cm de haut, jambes repliées.",ms:["Épaisseur du dos","Biceps"],d:2,bar:true,ch:true},
{id:"C7",f:"C",name:"Exercice C7",desc:"Technique et respiration identiques à C4. Seule la position des mains change : les paumes sont tournées vers l'avant (pronation). Cible l'épaisseur du haut du dos.",ms:["Épaisseur du haut du dos"],d:2,bar:true,ch:false},
{id:"C8",f:"C",name:"Exercice C8",desc:"Respiration identique à C4. Position des jambes identique à C5. Position des mains identique à C7 (pronation, paumes vers l'avant). Cible l'épaisseur du haut du dos.",ms:["Épaisseur du haut du dos"],d:3,bar:true,ch:true},
{id:"C9",f:"C",name:"Exercice C9",desc:"Respiration identique à C4. Position des jambes identique à C6. Position des mains identique à C7 (pronation, paumes vers l'avant). Cible l'épaisseur du haut du dos.",ms:["Épaisseur du haut du dos"],d:3,bar:true,ch:true},
{id:"D",f:"D",name:"Exercice D",desc:"Dips arrière : main gauche agrippe le bord gauche d'une chaise, main droite agrippe le bord droit de la même chaise. Talons quasiment joints sur l'autre chaise, jambes légèrement pliées. Chaises alignées face à face, distantes d'environ un mètre. Inspirer en pliant les bras, descendre le plus bas possible. Tendre les bras pour remonter en soufflant.",ms:["Triceps"],d:1,bar:false,ch:true},
{id:"E",f:"E",name:"Exercice E",desc:"Squat unilatéral dans le cadre d'une porte (tenir les montants à hauteur de taille). Ne descendre qu'à une petite flexion puis remonter jambe tendue. Inspirer en descendant, souffler en remontant. Exercer toujours une jambe complètement, puis l'autre.",ms:["Cuisses","Fessiers"],d:1,bar:false,ch:false},
{id:"E1",f:"E",name:"Exercice E1",desc:"Même technique qu'E. Descendre plus bas : jusqu'à ce que la cuisse soit parallèle au sol, puis remonter jambe tendue.",ms:["Cuisses","Fessiers"],d:1,bar:false,ch:false},
{id:"E2",f:"E",name:"Exercice E2",desc:"Même technique qu'E1. Descendre le plus bas possible, puis remonter jambe tendue.",ms:["Cuisses","Fessiers"],d:2,bar:false,ch:false},
{id:"E3",f:"E",name:"Exercice E3",desc:"Même technique qu'E1. Descendre un peu sous la position moyenne, remonter un peu au-dessus sans tendre la jambe. Aller très vite sans jamais relever complètement la jambe ou descendre à fond.",ms:["Cuisses","Fessiers"],d:2,bar:false,ch:false},
{id:"E4",f:"E",name:"Exercice E4",desc:"Debout, jambes bien écartées. Plier la jambe droite en gardant la jambe gauche tendue, descendre le plus bas possible, remonter en gardant la jambe gauche tendue. Descendre ensuite en pliant la jambe gauche et en gardant la jambe droite tendue, puis remonter. Recommencer.",ms:["Cuisses","Fessiers"],d:2,bar:false,ch:false},
{id:"E5",f:"E",name:"Exercice E5",desc:"Reprendre la technique de E4. Cette fois, faire la jambe droite sans s'arrêter, puis la jambe gauche. Peu à peu atteindre une durée de 3 min en pliant uniquement la jambe droite. Se reposer 1 min 30 max. Ensuite tenir 3 min en pliant uniquement la jambe gauche.",ms:["Cuisses","Fessiers"],d:3,bar:false,ch:false},
{id:"E6",f:"E",name:"Exercice E6",desc:"Tenir debout, pieds très rapprochés et parallèles. En inspirant, plier les jambes et descendre le plus bas possible, tenir 2 secondes pour étirer les muscles, puis remonter. Ensuite écarter un peu les pieds (pointe vers l'extérieur), descendre le plus bas possible. Faire une dernière minute en descendant toujours le plus bas possible, pieds bien écartés.",ms:["Cuisses","Fessiers"],d:3,bar:false,ch:false},
{id:"E7",f:"E",name:"Exercice E7",desc:"Même principe qu'E2, se positionner dos à un mur. En descendant, les mains viennent s'appuyer une fraction de seconde sur le mur pour stabiliser. Faire les 2/3 du mouvement complet. C'est la cuisse qui fait la majeure partie de l'effort de remontée, sans aide des bras.",ms:["Cuisses","Fessiers"],d:4,bar:false,ch:false},
{id:"F",f:"F",name:"Exercice F",desc:"Sauts verticaux : bondir le plus verticalement possible et atterrir sur le premier tiers de la plante des pieds en pliant les jambes pour amortir. Dès que les cuisses sont parallèles au sol, rebondir immédiatement sans pause. Jambes légèrement pliées en l'air.",ms:["Cuisses","Mollets"],d:1,bar:false,ch:false},
{id:"F1",f:"F",name:"Exercice F1",desc:"Tenir assis, dos appuyé contre un mur, cuisses parallèles au sol. Tenir le plus longtemps possible. Peu à peu parvenir à tenir 3 minutes sans bouger.",ms:["Cuisses","Mollets"],d:2,bar:false,ch:false},
{id:"F2",f:"F",name:"Exercice F2",desc:"Tenir debout, jambes écartées, dos bien droit, cuisses presque parallèles au sol. Rester dans cette position le plus longtemps possible. Semaine après semaine, parvenir à tenir 3 minutes d'affilée.",ms:["Cuisses","Mollets"],d:2,bar:false,ch:false},
{id:"F3",f:"F",name:"Exercice F3",desc:"Variante de F1, plus difficile. Une seule jambe est en appui au sol. La cheville de l'autre jambe est posée sur le genou de la jambe en appui. Tenir la position le plus longtemps possible. Objectif : 3 minutes d'affilée par jambe.",ms:["Cuisses","Mollets"],d:3,bar:false,ch:false},
{id:"G",f:"G",name:"Exercice G",desc:"Allongé sur le sol ou un tapis. Rapprocher la poitrine du bassin en arrondissant le dos. Ne pas se relever en s'aidant des hanches, ne pas décoller le bas du dos. Souffler en se recroquevillant tout en rentrant le ventre. Inspirer en revenant au point de départ. Cuisses à un angle droit avec le buste.",ms:["Abdominaux (partie haute)"],d:1,bar:false,ch:false},
{id:"H",f:"H",name:"Exercice H",desc:"Se suspendre à la barre. En inspirant, ramener les genoux vers la poitrine ; ventre maintenu rentré. Descendre en soufflant jusqu'à ce que les cuisses soient parallèles au sol. Jambes toujours pliées. Ne pas relâcher le ventre. Recommencer en ramenant à nouveau les genoux vers la poitrine.",ms:["Abdominaux (partie basse)"],d:1,bar:true,ch:false},
{id:"I",f:"I",name:"Exercice I",desc:"Tractions à la barre longue, prise pronation (paumes vers l'avant), largeur légèrement supérieure aux épaules. Amener la nuque contre la barre à la force du dos et des bras. Descendre à peine et remonter très vite. Inspirer en descendant, souffler en montant.",ms:["Largeur du dos"],d:2,bar:true,ch:false},
{id:"I1",f:"I",name:"Exercice I1",desc:"Lisez le descriptif de I. La technique est similaire. La seule différence réside dans l'amplitude : descendre jusqu'à ce que les bras soient parallèles au sol, remonter le plus vite possible (nuque contre la barre). Ne pas descendre plus bas que la ligne parallèle formée par les bras.",ms:["Largeur du dos"],d:2,bar:true,ch:false},
{id:"I2",f:"I",name:"Exercice I2",desc:"Même position qu'I1. Descendre complètement en tendant les bras, puis remonter jusqu'à ce que la nuque soit en contact avec la barre. Inspirer en descendant, souffler en remontant.",ms:["Largeur du dos"],d:2,bar:true,ch:false},
{id:"I3",f:"I",name:"Exercice I3",desc:"Reprendre la technique décrite en C et changer la position des mains : paume vers l'avant (pronation). En fonction des besoins, modifier l'amplitude du mouvement (1/3, 1/2 ou 2/3). Remplace I, I1 ou I2 si pas de barre longue.",ms:["Dos","Bras"],d:3,bar:true,ch:false},
{id:"I4",f:"I",name:"Exercice I4",desc:"Reprendre la technique décrite pour I2. Pratiquer de la même façon mais le menton monte ici au-dessus de la barre. Attention à ne pas trop pencher la tête en arrière pour faire passer absolument le menton au-dessus de la barre, risque de blesser les cervicales.",ms:["Largeur du dos"],d:3,bar:true,ch:false},
{id:"I5",f:"I",name:"Exercice I5",desc:"Technique presque identique à celle décrite pour I4. La différence réside dans la position des mains : au lieu d'être tournées vers l'avant, les paumes sont face à face. Descendre complètement en tendant les bras, remonter le menton au-dessus de la barre en soufflant.",ms:["Dos","Bras"],d:3,bar:true,ch:false},
{id:"I6",f:"I",name:"Exercice I6",desc:"Reprendre la technique et la respiration indiquées pour C4. Cette fois, les paumes sont face à face (prise neutre). L'idéal est d'utiliser une table. En fonction de la progression, adopter la position débutant, entraîné ou confirmé.",ms:["Épaisseur du dos"],d:2,bar:true,ch:true},
{id:"I7",f:"I",name:"Exercice I7",desc:"Même technique qu'I1, sauf que faire les deux tiers du mouvement complet et non la moitié. Descendre jusqu'à ce que les bras soient presque tendus en inspirant, souffler en remontant.",ms:["Largeur du dos"],d:3,bar:true,ch:false},
{id:"I8",f:"I",name:"Exercice I8",desc:"Technique et respiration identiques à C4. La largeur de la prise est cette fois égale à environ deux fois la largeur des épaules. Les paumes sont dirigées vers l'avant (pronation). Cible l'épaisseur du haut du dos.",ms:["Épaisseur du haut du dos"],d:3,bar:true,ch:true},
{id:"J",f:"J",name:"Exercice J",desc:"Mains à plat sur une chaise, pieds posés sur un support à environ 100cm de haut (à environ 1m80 de distance). Corps plié en V, fesses vers le plafond. Descendre la tête entre les mains le plus bas possible, souffler en remontant. Pieds restent proches du bord du support.",ms:["Épaules","Partie supérieure des pectoraux"],d:2,bar:false,ch:true},
{id:"J1",f:"J",name:"Exercice J1",desc:"Cet exercice requiert les mêmes conditions que J. La distance entre les deux mains doit être légèrement supérieure à la largeur des épaules (mains plus rapprochées qu'en J).",ms:["Épaules","Partie supérieure des pectoraux"],d:3,bar:false,ch:true},
{id:"J2",f:"J",name:"Exercice J2",desc:"Faire J sur les poings et non plus les paumes à plat. Si le support est trop dur et blesse les poings, mettre une serviette pliée ou un coussin peu épais. Les poings sont alignés comme si on tenait une barre joignant les deux mains.",ms:["Épaules","Partie supérieure des pectoraux"],d:3,bar:false,ch:true},
{id:"J3",f:"J",name:"Exercice J3",desc:"Faire J1 sur les poings. La distance entre les mains est ici inférieure à celle indiquée en J2 (mains encore plus rapprochées qu'en J2).",ms:["Épaules","Partie supérieure des pectoraux"],d:4,bar:false,ch:true},
{id:"K",f:"K",name:"Exercice K",desc:"Poser les coudes au sol, écartés de la largeur des épaules. Les mains, paumes à plat sur le sol, sont un peu moins écartées que les coudes et posées un peu en avant de la tête. En gardant les paumes au sol, tendre les bras en soufflant. Revenir en inspirant. Éviter de trop écarter les coudes.",ms:["Triceps"],d:2,bar:false,ch:false},
{id:"K1",f:"K",name:"Exercice K1",desc:"Besoin d'une table, bureau, étagère ou barre fixée à environ un mètre du sol. Sur la pointe des pieds, saisir le support. Exécuter une flexion complète des bras, puis remonter en tendant les bras. Ne pas donner d'à-coups pour remonter plus facilement.",ms:["Triceps"],d:2,bar:false,ch:false},
{id:"K2",f:"K",name:"Exercice K2",desc:"Se placer face à un mur, poser les mains à environ 150cm de hauteur. Sur la pointe des pieds, effectuer une flexion jusqu'à ce que la tête touche le mur. Remonter au point de départ. Progresser en abaissant les mains (6 niveaux selon la hauteur du support).",ms:["Triceps"],d:1,bar:false,ch:true},
{id:"K3",f:"K",name:"Exercice K3",desc:"Cet exercice ressemble à K1 mais les paumes sont tournées vers soi. Appuyer les chaises contre un mur. Fixer une barre (ou une corde/sangle) entre les dossiers des chaises à environ 45cm du sol. La barre doit pouvoir tourner lors de l'exécution. Progression par rapprochement progressif des jambes.",ms:["Triceps"],d:3,bar:true,ch:true},
{id:"L",f:"L",name:"Exercice L",desc:"En appui sur les mains, corps tendu, pointe des pieds au sol. En inspirant, effectuer une rotation du corps sur la droite de façon à ce que le poids soit majoritairement supporté par le bras droit, tout en pliant le bras gauche. Souffler en remontant, puis faire une rotation sur la gauche.",ms:["Pectoraux","Épaules","Triceps"],d:2,bar:false,ch:false},
{id:"M",f:"M",name:"Exercice M",desc:"Allongé sur le ventre sur un support d'environ 10cm de haut. Les hanches dépassent légèrement du support. Descendre les mains vers le sol, les coller à la nuque (ou bras tendus). Remonter jusqu'à ce que le corps soit horizontal (parallèle au sol). Ne jamais aller plus haut ni cambrer.",ms:["Bas du dos"],d:1,bar:false,ch:false},
{id:"N",f:"N",name:"Exercice N",desc:"Couché sur le côté sur un support d'un minimum de 40cm de hauteur. Les pieds sont fixés. Faire une flexion du buste en inspirant en allant le plus haut possible. Souffler en descendant. Ne pas descendre trop bas les premières fois.",ms:["Obliques"],d:2,bar:false,ch:true},
{id:"N1",f:"N",name:"Exercice N1",desc:"Allongé sur le côté, de préférence sur un tapis. Sans à-coups ni élan, décoller le buste du sol. Monter le plus haut possible à chaque répétition.",ms:["Obliques"],d:1,bar:false,ch:false},
{id:"O",f:"O",name:"Exercice O",desc:"Allongé sur le dos, jambes pliées, pieds à plat sur le sol. En soufflant, remonter en faisant une rotation vers la gauche afin que le coude droit vienne quasiment toucher le genou gauche. Redescendre en inspirant. Remonter en faisant une rotation vers la droite. Penser à bien rentrer le ventre pendant toute la série.",ms:["Abdominaux","Obliques"],d:1,bar:false,ch:false},
{id:"P",f:"P",name:"Exercice P",desc:"Allongé sur le dos, jambes fléchies, pieds à plat sur le sol. En soufflant, se relever jusqu'à aller toucher les cuisses. Inspirer en redescendant. Ne jamais tirer sur la nuque. Ne pas creuser les reins pour remonter plus facilement.",ms:["Abdominaux"],d:1,bar:false,ch:false},
{id:"Q",f:"Q",name:"Exercice Q",desc:"La main droite (ou gauche) est en appui sur une chaise. Les jambes sont tendues et écartées. Les pieds sont légèrement en arrière par rapport aux hanches. Fléchir le bras en inspirant, descendre le plus bas possible. Remonter en expirant en forçant avec l'épaule et le bras.",ms:["Épaules","Triceps","Pectoraux (partie latérale haute)"],d:2,bar:false,ch:true},
{id:"Q1",f:"Q",name:"Exercice Q1",desc:"Technique presque identique à Q. Le corps doit être le plus droit possible. Une des jambes est tendue dans le prolongement du corps, l'autre sert à conserver l'équilibre. Le support est à environ 25cm de haut. Descendre toujours le plus bas possible.",ms:["Épaules","Triceps","Pectoraux (partie latérale haute)"],d:3,bar:false,ch:false},
{id:"Q2",f:"Q",name:"Exercice Q2",desc:"Même technique que pour Q1, mais cette fois l'exercice est fait au sol, sans aucun support.",ms:["Épaules","Triceps","Pectoraux (partie latérale haute)"],d:4,bar:false,ch:false},
{id:"R",f:"R",name:"Exercice R",desc:"Se placer en appui sur des barres parallèles ou des chaises assez hautes. Pieds ne touchent pas le sol. Hausser les épaules le plus haut possible en inspirant (les épaules se rapprochent des oreilles), abaisser les épaules le plus bas possible en expirant. Réaliser lentement avec grande concentration.",ms:["Trapèzes","Cou"],d:2,bar:false,ch:true},
{id:"S",f:"S",name:"Exercice S",desc:"S'allonger sur un banc ou une chaise, les pieds au sol. Descendre la tête en arrière, le plus bas possible, sans forcer pour ne pas blesser les vertèbres cervicales. Remonter la tête en pointant le menton vers la poitrine. Inspirer en descendant la tête en arrière, souffler en la remontant.",ms:["Cou"],d:1,bar:false,ch:true},
{id:"T",f:"T",name:"Exercice T",desc:"Tenir assis, les pieds bien à plat sur le sol (bloqués sous un support de préférence). Placer un manche à balai derrière les épaules. Effectuer des rotations à droite et à gauche le plus loin possible sans forcer. Ne pas bloquer la respiration. Cuisses et fessiers ne bougent pas.",ms:["Obliques","Abdominaux"],d:1,bar:false,ch:false},
{id:"U",f:"U",name:"Exercice U",desc:"S'allonger sur un tapis. Ramener les jambes presque tendues au-dessus de la tête en enroulant la colonne vertébrale pour faire passer les pieds par-dessus la tête. En gardant les jambes presque tendues, enrouler la colonne. Revenir au point de départ en déroulant progressivement.",ms:["Abdominaux","Souplesse de la colonne vertébrale"],d:2,bar:false,ch:false},
{id:"V",f:"V",name:"Exercice V",desc:"Couché sur le sol, faire l'essuie-glace avec les jambes presque tendues pendant trois minutes. Ne pas bloquer la respiration, ne pas creuser les reins. Veiller à ne pas ramener les reins en descendant de chaque côté.",ms:["Muscles de la taille","Souplesse de la colonne vertébrale"],d:2,bar:false,ch:false},
{id:"W",f:"W",name:"Exercice W",desc:"Debout sur une cale d'au moins 15cm de haut, en appui sur un seul pied. S'appuyer d'une main sur un mur ou meuble pour l'équilibre. Descendre le talon le plus bas possible en étirant le mollet, puis remonter sur la pointe du pied. Aller lentement pour bien sentir l'étirement et la contraction complète. Exercer le mollet droit, puis le gauche.",ms:["Mollets"],d:2,bar:false,ch:false},
{id:"X",f:"X",name:"Exercice X",desc:"Debout ou assis sur un support suffisamment élevé (chaise), tenir un manche à balai derrière les épaules. Lentement, effectuer une rotation vers la droite puis une rotation vers la gauche. Bloquer le bassin. Aller le plus loin possible sans jamais forcer.",ms:["Muscles de la taille","Souplesse de la colonne vertébrale"],d:2,bar:false,ch:false},
{id:"Y",f:"Y",name:"Exercice Y",desc:"La meilleure position : allongé sur un tapis avec un coussin épais sous les côtes. Le bras est dans le prolongement du corps, sur le sol. Tourner la tête lentement, sans jamais forcer. Ne jamais aller trop loin. Faire une série allongé sur le côté droit, une série allongé sur le côté gauche.",ms:["Cou"],d:2,bar:false,ch:false},
{id:"Z",f:"Z",name:"Exercice Z",desc:"Exercice fondamental en 3 étapes. 1) Pieds parallèles, mains contre le sol, enrouler la colonne vertébrale. 2) Tendre les bras en arquant le dos pour soulever le bassin (hauteur des hanches). 3) Essayer de tendre les bras en arquant complètement le dos (pont). Tenir chaque position. Objectif progressif : quelques répétitions de 15 à 30 secondes.",ms:["Souplesse de la colonne vertébrale"],d:1,bar:false,ch:false},
];
const EXO={};EL.forEach(e=>EXO[e.id]=e);

// ═══════════════════════════════ SOUPLESSE (35 exercices du livre p.118–127) ═══════════════════════════════
const STRETCH=[
// HAUT DU CORPS
{n:1,z:"h",title:"Mains entrecroisées au-dessus de la tête",desc:"Mains entrecroisées, paumes vers le plafond. Poussez en tendant les bras vers le haut. Ressentez l'étirement le long des bras et entre les omoplates.",dur:30},
{n:2,z:"h",title:"Variante : paumes jointes au-dessus de la tête",desc:"Même position mais paumes se touchent plutôt que d'être entrecroisées. Pousse vers le haut.",dur:30},
{n:3,z:"h",title:"Attraper les mains dans le dos",desc:"Levez le bras gauche à la verticale, descendez l'avant-bras gauche dans le dos, montez l'avant-bras droit pour attraper la main gauche. Faites les deux côtés. Si impossible, utilisez une serviette.",dur:30},
{n:4,z:"h",title:"Paumes jointes dans le dos",desc:"Debout, montez vos avant-bras dans le dos et tentez de faire se toucher les paumes. Poussez en respirant calmement. Objectif : coller les paumes l'une contre l'autre.",dur:30},
{n:5,z:"h",title:"Suspension à la barre fixe",desc:"Suspendez-vous à une barre fixe. Si trop lourd, laissez les orteils en contact avec le sol. Variez en ramenant les genoux vers la poitrine ou les talons vers les fesses.",dur:30},
{n:6,z:"h",title:"Étirement des épaules à la barre (dos)",desc:"Debout à la verticale de la barre, attrapez-la derrière vous, paumes vers le plafond. Reculez les pieds et pliez les jambes progressivement pour sentir l'étirement dans les épaules.",dur:30},
{n:7,z:"h",title:"Inclinaison latérale du buste",desc:"Debout, écart pieds légèrement > largeur des épaules. Penchez-vous sur le côté, la main descend lentement le long de la jambe vers la cheville. Plus vous descendez, plus l'étirement gagne la taille.",dur:30},
{n:8,z:"h",title:"Étirement du haut du dos en tailleur ou lotus",desc:"Assis en tailleur ou lotus. Entrecroisez les doigts derrière le crâne. Penchez-vous vers l'avant. Respirez profondément pour amplifier l'étirement du haut du dos.",dur:30},
{n:9,z:"h",title:"Étirement total allongé",desc:"Allongé sur le sol, tendez simultanément les bras vers l'arrière et les jambes en poussant les orteils le plus loin possible. Imaginez-vous écartelé. Respirez amplement.",dur:30},
{n:10,z:"h",title:"Inclinaison latérale de la tête (cou)",desc:"Assis ou debout, penchez progressivement la tête sur le côté. L'effort se fait à la BASE du cou, pas sous l'oreille. Le buste reste droit. Faites les deux côtés.",dur:20},
{n:11,z:"h",title:"Flexion de la nuque allongé",desc:"Allongé au sol, entrecroisez les doigts et saisissez votre nuque. Ramenez progressivement la tête vers l'avant jusqu'à sentir une tension agréable. Ne forcez jamais.",dur:20},
{n:12,z:"h",title:"Étirement dos avec paumes jointes",desc:"Reprenez la position n°4 (paumes jointes dans le dos). Penchez-vous en avant avec l'intention de poser la poitrine sur la cuisse. Faites les deux côtés.",dur:30},
{n:13,z:"h",title:"Rotation du buste assis",desc:"Assis au sol, jambe D tendue, jambe G pliée pied contre genou D. Coude D contre genou G, main G derrière. Tournez le buste. Faites les deux côtés.",dur:30},
{n:14,z:"h",title:"Étirement des poignets à 4 pattes",desc:"À quatre pattes, tournez les poignets pour que les doigts pointent vers vos genoux. Reculez le bassin en pliant les jambes pour ressentir l'étirement dans les avant-bras.",dur:20},
{n:15,z:"h",title:"Flexion des poignets",desc:"Appuyez le coude D sur la cuisse, saisissez le dessus de la main D avec la main G. Exercez une pression modérée. Faites les deux côtés.",dur:20},
// MILIEU DU CORPS
{n:16,z:"m",title:"Genou vers la poitrine allongé",desc:"Allongé sur le dos, saisissez votre genou D à deux mains, tirez-le vers la poitrine, l'autre jambe tendue. Faites ensuite avec le genou G.",dur:30},
{n:17,z:"m",title:"Étirement des ischio-jambiers assis",desc:"Assis, jambe D tendue, jambe G repliée. Penchez-vous en avant, progressez le long de la jambe tendue. Objectif : poser la poitrine sur la cuisse. Faites les deux côtés.",dur:30},
{n:18,z:"m",title:"Étirement de la hanche pliée allongé",desc:"Variante du n°17 en position allongée sur le côté. Pliez une jambe en arrière pour aussi sentir l'étirement de la hanche du côté de la jambe pliée.",dur:30},
{n:19,z:"m",title:"Flexion avant jambes légèrement pliées",desc:"Debout, jambes légèrement pliées. Penchez-vous en avant pour toucher le sol avec les doigts puis la paume à plat. Sentez l'étirement dans le bas du dos et l'arrière des cuisses.",dur:30},
{n:20,z:"m",title:"Flexion avant avec inclinaison latérale",desc:"Variante du n°19 : au lieu de se pencher vers l'avant, penchez-vous alternativement sur le côté droit et sur le côté gauche.",dur:30},
{n:21,z:"m",title:"Flexion avant en tailleur",desc:"En tailleur, penchez-vous en avant. Objectif progressif : coudes au sol, puis front au sol. Gardez toujours les fesses au sol. Ne forcez jamais.",dur:30},
{n:22,z:"m",title:"Fente avant — étirement du psoas",desc:"Genou arrière au sol (protection sous le genou si besoin). Avancez le bassin en pliant la jambe avant. Le bassin doit avancer ET s'abaisser simultanément. Dos droit. Faites les deux côtés.",dur:30},
{n:23,z:"m",title:"Grand écart avant progressif",desc:"Depuis la fente, avancez progressivement le pied avant jusqu'à ce que l'étirement devienne légèrement douloureux. Alternez jambe D et G en avant. Utilisez des chaises pour vous soutenir.",dur:30},
{n:24,z:"m",title:"Jambes écartées allongé sur le dos",desc:"Couché sur le dos, attrapez chaque genou pour aider vos jambes à s'écarter. Le bas du dos doit rester collé au sol. Ne creusez pas les reins.",dur:30},
{n:25,z:"m",title:"Grand écart latéral progressif",desc:"Debout, penchez-vous en avant, posez les paumes à plat sur le sol, écartez les jambes jusqu'à ressentir l'étirement à l'intérieur des cuisses. Sol lisse recommandé.",dur:30},
{n:26,z:"m",title:"Étirement aine assis sur chaise",desc:"Assis sur le bord d'une chaise, jambes et pieds très écartés. Bras croisés, penchez-vous en avant, essayez de poser les coudes au sol.",dur:30},
{n:27,z:"m",title:"Fessier profond en position repliée",desc:"Comme n°18. Cette fois, essayez de poser les COUDES au sol. Commencez par les mains, progressez séance après séance.",dur:30},
{n:28,z:"m",title:"Étirement des genoux à quatre pattes",desc:"À genoux sur sol lisse. Écartez presque au maximum les cuisses. Coudes au sol, poussez les fesses vers l'arrière comme pour s'asseoir entre les mollets. Mollets parallèles.",dur:30},
{n:29,z:"m",title:"Rotation de la colonne vertébrale",desc:"Allongé sur le dos, pliez une jambe et laissez le genou descendre de l'autre côté, épaules collées au sol. Rotation vertébrale. Les deux côtés.",dur:30},
// BAS DU CORPS
{n:30,z:"b",title:"Quadriceps allongé sur le côté",desc:"Couché sur le côté, une jambe tendue. L'autre pliée avec le pied dans le prolongement du mollet (doigts vers l'arrière). Penchez-vous progressivement en arrière pour étirer l'avant de la cuisse.",dur:30},
{n:31,z:"b",title:"Seiza stretch — assis entre les mollets",desc:"À genoux, jambes écartées pour vous asseoir entre vos mollets. Penchez-vous en arrière. Objectif final : se coucher sur le dos, reins collés au sol. Progressez par étapes.",dur:30},
{n:32,z:"b",title:"Fessier en figure 4 allongé",desc:"Couché sur le dos, pied D à plat contre un mur, mollet parallèle au sol. Cheville G sur la cuisse D côté genou. Poussez l'intérieur du genou G vers le mur. Faites les deux côtés.",dur:30},
{n:33,z:"b",title:"Mollet et tendon d'Achille à 4 pattes",desc:"À quatre pattes, relevez légèrement un talon. Penchez-vous en avant sans décoller davantage le talon. Essayez de poser le talon au sol. Faites les deux côtés.",dur:20},
{n:34,z:"b",title:"Étirement du mollet sur cale",desc:"Avant-pied sur cale ou marche d'escalier. Poussez les talons vers le bas comme si vos orteils voulaient toucher le tibia. Ressentez l'étirement dans le mollet.",dur:30},
{n:35,z:"b",title:"Étirement du dessus du pied",desc:"Debout, posez le dessus du pied au sol (orteils vers l'arrière). Pesez légèrement. Très doux, ne jamais forcer. Pliez l'autre jambe si besoin.",dur:15},
];

