// ═══════════════════════════════ DONNÉES FÉMININES ═══════════════════════════════
const EL_F=[
// ── Bas du corps ──────────────────────────────────────────────────────────────
{id:"f_A",f:"A",name:"Exercice A",desc:"Debout, pieds rapprochés et parallèles. Inspirer, plier les jambes et descendre le plus bas possible, tenir 2 s en bas, puis remonter en soufflant. Objectif : 1 min de travail puis 1 min pieds écartés.",ms:["Cuisses","Hanches","Fessiers"],d:1,bar:false,ch:false},
{id:"f_A1",f:"A",name:"Exercice A1",desc:"Squat 1 jambe dans le cadre d'une porte, quart de mouvement. Se tenir aux montants à la hauteur de la taille ; descendre jusqu'à ce que la cuisse soit parallèle au sol, jambe tendue en avant, puis remonter en soufflant.",ms:["Cuisses","Hanches","Fessiers"],d:1,bar:false,ch:false},
{id:"f_B",f:"B",name:"Exercice B",desc:"Squat complet 1 jambe dans le cadre de porte, amplitude maximale. Descendre le plus bas possible, jambe libre tendue en avant, inspirant en descendant et soufflant en remontant. Alterner les jambes.",ms:["Cuisses","Hanches","Fessiers"],d:1,bar:false,ch:false},
{id:"f_B1",f:"B",name:"Exercice B1",desc:"Squat 1 jambe dans le cadre de porte, cuisse parallèle au sol. Descendre jusqu'à ce que la cuisse soit parallèle, ne pas s'aider des bras en descendant, remonter en soufflant, jambe toujours tendue.",ms:["Cuisses","Hanches","Fessiers"],d:1,bar:false,ch:false},
{id:"f_B2",f:"B",name:"Exercice B2",desc:"Squat 1 jambe encore plus bas : reprendre la technique de B1 mais descendre le plus bas possible puis remonter jambe tendue.",ms:["Cuisses","Hanches","Fessiers"],d:1,bar:false,ch:false},
{id:"f_C",f:"C",name:"Exercice C",desc:"Sauts verticaux. Bondir le plus haut possible, atterrir sur le premier tiers du pied et rebondir immédiatement sans temps d'arrêt, cuisses parallèles au sol à chaque réception. Ne jamais poser les pieds à plat.",ms:["Cuisses","Hanches","Fessiers"],d:1,bar:false,ch:false},
{id:"f_D",f:"D",name:"Exercice D",desc:"Marche en canard : s'accroupir au maximum et avancer en canard. Compter chaque pas pour une répétition.",ms:["Cuisses","Hanches","Fessiers"],d:1,bar:false,ch:false},
{id:"f_E",f:"E",name:"Exercice E",desc:"Montée sur chaise 1 jambe. Choisir une chaise solide (ou meuble bas), monter et descendre avec une seule jambe, jambe libre ne touchant pas le sol. Alterner jambe droite et gauche.",ms:["Cuisses","Hanches","Fessiers"],d:1,bar:false,ch:true},
{id:"f_F",f:"F",name:"Exercice F",desc:"Fentes latérales : plier une jambe en gardant l'autre tendue, descendre le plus bas possible sans décoller les pieds du sol. L'illustration montre le travail de la jambe droite ; la jambe gauche accompagne le mouvement en restant tendue.",ms:["Cuisses","Hanches","Fessiers"],d:1,bar:false,ch:false},
{id:"f_G",f:"G",name:"Exercice G",desc:"Extensions de hanche à quatre pattes. Rentrer le ventre, lever une jambe vers l'arrière en concentrant le travail sur le fessier, le plus haut possible sans cambrer. Redescendre lentement en inspirant, amener le genou vers la poitrine.",ms:["Cuisses","Hanches","Fessiers"],d:1,bar:false,ch:false},
{id:"f_G1",f:"G",name:"Exercice G1",desc:"Extensions de hanche à quatre pattes, variante latérale. Lever une jambe sur le côté en concentrant l'effort sur le fessier, de manière lente et régulière. La jambe doit rester pliée à l'équerre pendant tout le mouvement.",ms:["Cuisses","Hanches","Fessiers"],d:1,bar:false,ch:false},
{id:"f_H",f:"H",name:"Exercice H",desc:"Flexions du buste debout, jambes légèrement pliées : se pencher en avant jusqu'à ce que le buste soit parallèle au sol, bras tendus dans le prolongement du dos, puis remonter lentement en soufflant. Ne pas cambrer, ne pas aller trop loin en arrière.",ms:["Cuisses","Hanches","Fessiers"],d:1,bar:false,ch:false},
// ── Taille fine – Ventre plat ─────────────────────────────────────────────────
{id:"f_I",f:"I",name:"Exercice i",desc:"Transverse allongée : couchée sur le dos, reins plaqués, jambes pliées, pieds à plat. Souffler lentement en rentrant le ventre au maximum sous les côtes ; viser 30 s d'expiration. Tenir en apnée 3-7 s lorsque le ventre est rentré au maximum.",ms:["Taille fine","Ventre plat"],d:1,bar:false,ch:false},
{id:"f_I1",f:"I",name:"Exercice i1",desc:"Transverse allongée variante : même position de base, mains poussant les hanches vers les pieds, épaules restant basses. En inspirant, souffler en rentrant le ventre au maximum, impression de ceinture qui se resserre progressivement.",ms:["Taille fine","Ventre plat"],d:1,bar:false,ch:false},
{id:"f_I2",f:"I",name:"Exercice i2",desc:"Transverse allongée jambe relevée : même position de base, relever une jambe droite, poser la main gauche sur la cuisse droite. Souffler lentement en rentrant le ventre au maximum, viser 30 s d'expiration, tenir en apnée 3-7 s.",ms:["Taille fine","Ventre plat"],d:1,bar:false,ch:false},
{id:"f_I3",f:"I",name:"Exercice i3",desc:"Transverse couché sur le côté : couchée sur le côté droit, jambes légèrement pliées, tête reposant sur le bras droit, bras gauche le long du corps. Souffler lentement en rentrant le ventre au maximum, faire comme si la partie basse du ventre s'abaissait jusqu'à rejoindre la colonne vertébrale.",ms:["Taille fine","Ventre plat"],d:1,bar:false,ch:false},
{id:"f_I4",f:"I",name:"Exercice i4",desc:"Transverse jambes à 90° : couchée sur le dos, jambes serrées relevées à 90°, reins plaqués. Souffler en rentrant le ventre au maximum ; une fois rentré, inspiration et expiration uniquement par le thorax, ventre immobile.",ms:["Taille fine","Ventre plat"],d:1,bar:false,ch:false},
{id:"f_I5",f:"I",name:"Exercice i5",desc:"Transverse jambes croisées relevées : couchée sur le dos, jambes croisées, pliées et relevées, reins plaqués. Souffler en rentrant le ventre au maximum ; une fois rentré, respirer uniquement par le thorax, ventre immobile.",ms:["Taille fine","Ventre plat"],d:1,bar:false,ch:false},
{id:"f_I6",f:"I",name:"Exercice i6",desc:"Transverse jambes croisées relevées, rythme rapide : même position qu'i5. Une fois la technique maîtrisée, garder le ventre rentré et inspirer/souffler rapidement par le thorax, en marchant au maximum. Rythme rapide pour i6.",ms:["Taille fine","Ventre plat"],d:1,bar:false,ch:false},
{id:"f_J",f:"J",name:"Exercice J",desc:"Transverse assis : assise, mains à plat sur les cuisses, dos droit, jambes légèrement écartées. Souffler lentement en rentrant le ventre au maximum sous les côtes, mains poussant vers le bas, étirer le cou vers le haut. Apnée 3-7 s lorsque le ventre est rentré au maximum.",ms:["Taille fine","Ventre plat"],d:1,bar:false,ch:false},
{id:"f_J1",f:"J",name:"Exercice J1",desc:"Transverse à genoux : à genoux, jambes légèrement écartées, mains sur hanches ou cuisses, dos droit. Souffler lentement en rentrant le ventre au maximum sous les côtes, viser 30 s d'expiration. Tenir en apnée 3-7 s.",ms:["Taille fine","Ventre plat"],d:1,bar:false,ch:false},
{id:"f_J2",f:"J",name:"Exercice J2",desc:"Transverse debout : jambes dans le prolongement du corps, mains sur les hanches, dos droit. Fléchir légèrement les jambes, souffler lentement en rentrant le ventre au maximum. Viser 30 s d'expiration, tenir en apnée 3-7 s.",ms:["Taille fine","Ventre plat"],d:1,bar:false,ch:false},
{id:"f_K",f:"K",name:"Exercice K",desc:"Rotations du buste avec bâton (ou manche à balai) tenu derrière les épaules. Debout ou assise sur un support surélevé, effectuer une rotation vers la droite puis vers la gauche, sans bloquer les hanches. Pencher légèrement en rentrant le ventre. 3 min sans pause.",ms:["Taille fine","Ventre plat"],d:1,bar:false,ch:false},
{id:"f_L",f:"L",name:"Exercice L",desc:"Crunchs inversés : allongée sur le dos, se rapprocher du bas de votre bassin en ramenant les épaules vers les hanches sans décoller le bas du dos. Inspirer en descendant, souffler en remontant en rentrant le ventre.",ms:["Taille fine","Ventre plat"],d:1,bar:false,ch:false},
{id:"f_M",f:"M",name:"Exercice M",desc:"Sit-ups : couchée sur le dos, jambes fléchies, pieds bloqués sous un meuble. Inspirer profondément en remontant, puis redescendre lentement. Ne pas descendre à fond ni toucher le sol avec les épaules. Rentrer le ventre pendant toute la série.",ms:["Taille fine","Ventre plat"],d:1,bar:false,ch:false},
{id:"f_N",f:"N",name:"Exercice N",desc:"Essuie-glace : couchée sur le sol, jambes presque tendues, balancer les jambes alternativement de droite à gauche pendant 3 min. Ne pas croiser les reins, amener le ballon (les jambes) vers la tête. Ne pas forcer surtout pas.",ms:["Taille fine","Ventre plat"],d:1,bar:false,ch:false},
{id:"f_O",f:"O",name:"Exercice O",desc:"Enroulements vertébraux : allongée sur un tapis, glisser les mains sous les épaules et la tête, ramener les jambes presque tendues au-dessus du ventre, reins plaqués. Enrouler la colonne vertébrale pour faire passer les pieds par-dessus la tête.",ms:["Taille fine","Ventre plat"],d:1,bar:false,ch:false},
// ── Poitrine ──────────────────────────────────────────────────────────────────
{id:"f_P",f:"P",name:"Exercice P",desc:"Pompes entre 2 chaises, pieds au sol. En appui sur 2 chaises, descendre le plus bas possible sans poser les mains à même le sol, puis remonter. Amplitude maximale.",ms:["Pectoraux","Dorsaux"],d:1,bar:false,ch:true},
{id:"f_P1",f:"P",name:"Exercice P1",desc:"Pompes entre 2 chaises, amplitude réduite rapide. Même position qu'en P mais ne pas descendre à fond ni tendre les bras en remontant ; faire la partie « moyenne » du mouvement à vitesse élevée.",ms:["Pectoraux","Dorsaux"],d:1,bar:false,ch:true},
{id:"f_Q",f:"Q",name:"Exercice Q",desc:"Pompes prise large, mains sur chaises, pieds au sol. Amplitude réduite : ne pas descendre à fond ni tendre les bras complètement ; aller le plus vite possible.",ms:["Pectoraux","Dorsaux"],d:1,bar:false,ch:true},
{id:"f_R",f:"R",name:"Exercice R",desc:"Rowing inversé sous barre ou table, pieds au sol, position débutante. Trois séries avec 1 min 30 s de repos entre chaque série ; objectif 20-25 répétitions à la première série.",ms:["Dorsaux","Biceps"],d:1,bar:true,ch:false},
{id:"f_S",f:"S",name:"Exercice S",desc:"Pompes prise serrée entre 2 chaises, amplitude réduite rapide. Même exécution que P1 mais mains rapprochées.",ms:["Pectoraux","Dorsaux"],d:1,bar:false,ch:true},
{id:"f_T",f:"T",name:"Exercice T",desc:"Rowing inversé sous barre, position « débutante » (dos à plat). Deux séries séparées par une minute de repos, remplacer T par T1 dès possible, faire le maximum de répétitions à chaque série.",ms:["Dorsaux","Biceps"],d:1,bar:true,ch:false},
{id:"f_T1",f:"T",name:"Exercice T1",desc:"Rowing inversé sous barre, position « sportive » (corps plus incliné). Objectif : 20 à 25 répétitions à la première série.",ms:["Dorsaux","Biceps"],d:2,bar:true,ch:false},
{id:"f_U",f:"U",name:"Exercice U",desc:"Rowing inversé sous barre, pieds surélevés sur une chaise (niveau avancé). Voir p. 124-125.",ms:["Dorsaux","Biceps"],d:2,bar:true,ch:true},
// ── Bras ──────────────────────────────────────────────────────────────────────
{id:"f_V",f:"V",name:"Exercice V",desc:"Dips arrière, pieds au sol. En appui sur une chaise derrière soi, descendre en pliant les bras puis remonter.",ms:["Triceps"],d:1,bar:false,ch:true},
{id:"f_V1",f:"V",name:"Exercice V1",desc:"Dips arrière, pieds surélevés sur une chaise.",ms:["Triceps"],d:2,bar:false,ch:true},
{id:"f_X",f:"X",name:"Exercice X",desc:"Extensions triceps, mains sur support à environ 1 m de hauteur. Amplitude réduite, aller le plus vite possible.",ms:["Triceps"],d:2,bar:false,ch:false},
{id:"f_W",f:"W",name:"Exercice W",desc:"Curl biceps isométrique sous un meuble fixe. Tirer vers le haut en gardant la contraction maximale.",ms:["Biceps"],d:1,bar:false,ch:false},
{id:"f_Y",f:"Y",name:"Exercice Y",desc:"Tractions supination prise serrée à la barre. Objectif : six séries de dix répétitions.",ms:["Biceps","Dorsaux"],d:2,bar:true,ch:false},
];
const EXO_F={};EL_F.forEach(e=>EXO_F[e.id]=e);

